import{_ as o,o as e,c as t,a0 as r}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Síntese: Redes Neurais Construtivas","description":"","frontmatter":{},"headers":[],"relativePath":"30_Ciencia_e_Topologia/sintese-redes-neurais-construtivas.md","filePath":"30_Ciencia_e_Topologia/sintese-redes-neurais-construtivas.md","lastUpdated":1783623176000}'),s={name:"30_Ciencia_e_Topologia/sintese-redes-neurais-construtivas.md"};function i(d,a,n,c,l,m){return e(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="sintese-redes-neurais-construtivas" tabindex="-1">Síntese: Redes Neurais Construtivas <a class="header-anchor" href="#sintese-redes-neurais-construtivas" aria-label="Permalink to &quot;Síntese: Redes Neurais Construtivas&quot;">​</a></h1><blockquote><p>Dois artigos de referência sobre o paradigma construtivo em redes neurais artificiais, mapeados para a arquitetura NEXUS T4.</p></blockquote><h2 id="paper-1-—-sapri-1998" tabindex="-1">Paper 1 — SAPRI (1998) <a class="header-anchor" href="#paper-1-—-sapri-1998" aria-label="Permalink to &quot;Paper 1 — SAPRI (1998)&quot;">​</a></h2><p><strong>Título:</strong> Reconhecimento de Alvos utilizando Redes Neurais Construtivas <strong>Autores:</strong> Ernesto Cuadros Vargas, Humberto Costa de Sousa, André Carlos Ponce de Leon Ferreira de Carvalho (USP São Carlos) <strong>Publicação:</strong> IX Simpósio Brasileiro de Sensoriamento Remoto, Santos, 11-18 setembro 1998, INPE, p. 1247-1256 <strong>PDF:</strong> <code>docs/reference/Reconhecimento de Alvos utilizando Redes Neurais Construtivas.pdf</code></p><h3 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h3><p>Parte do projeto <strong>SAPRI</strong> (Sistema para Aquisição, Processamento e Reconhecimento de Imagens), desenvolvido para a <strong>Marinha do Brasil</strong> — reconhecimento de alvos (navios) em imagens de radar.</p><h3 id="algoritmos-construtivos-comparados" tabindex="-1">Algoritmos Construtivos Comparados <a class="header-anchor" href="#algoritmos-construtivos-comparados" aria-label="Permalink to &quot;Algoritmos Construtivos Comparados&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Algoritmo</th><th>Característica</th></tr></thead><tbody><tr><td><strong>Cascade Correlation</strong></td><td>Adiciona unidades ocultas uma a uma, congela pesos anteriores, treina nova unidade para maximizar correlação com erro residual</td></tr><tr><td><strong>Tower</strong></td><td>Constrói torre de camadas — cada nova camada recebe entrada da camada anterior + entrada original</td></tr><tr><td><strong>Pyramid</strong></td><td>Similar à Tower, mas cada nova camada recebe entrada de todas as camadas anteriores</td></tr><tr><td><strong>Upstart</strong></td><td>Adiciona neurônios &quot;filhos&quot; para corrigir erros de classificação de neurônios existentes</td></tr></tbody></table><h3 id="comentario" tabindex="-1">Comentário <a class="header-anchor" href="#comentario" aria-label="Permalink to &quot;Comentário&quot;">​</a></h3><p>O SAPRI usa quatro fases clássicas de ATR (Automatic Target Recognition):</p><ol><li><strong>Captura</strong> (sensor) → 2. <strong>Pré-processamento + Segmentação</strong> → 3. <strong>Extração/Seleção de Características</strong> → 4. <strong>Classificação</strong></li></ol><p>As redes construtivas atuam na fase 4, adaptando dinamicamente a topologia ao problema específico de classificação de embarcações.</p><h3 id="resumo" tabindex="-1">Resumo <a class="header-anchor" href="#resumo" aria-label="Permalink to &quot;Resumo&quot;">​</a></h3><p>O SAPRI é focado em aplicação prática — radar, navios, classificação. As redes construtivas são o <strong>meio</strong> (não o fim). Os algoritmos Tower/Pyramid/Upstart são menos conhecidos que Cascade Correlation, mas oferecem estratégias complementares de crescimento topológico.</p><hr><h2 id="paper-2-—-unicamp-1999-mais-util" tabindex="-1">Paper 2 — UNICAMP (1999, mais útil) <a class="header-anchor" href="#paper-2-—-unicamp-1999-mais-util" aria-label="Permalink to &quot;Paper 2 — UNICAMP (1999, mais útil)&quot;">​</a></h2><p><strong>Título:</strong> Redes Neurais Construtivas: Uma Abordagem Comparativa <strong>Autores:</strong> Leandro Nunes de Castro, Eduardo Masato Iyoda, Eurípedes Pinheiro, Fernando Von Zuben (UNICAMP) <strong>Publicação:</strong> IV Brazilian Conference on Neural Networks — IV Congresso Brasileiro de Redes Neurais, pp. 102-107, July 20-22, 1999, ITA, São José dos Campos — SP, Brazil <strong>PDF:</strong> <code>docs/reference/.xdp-Redes Neurais Construtivas_ Uma Abordagem Comparativa.pdf-IGsps4</code> (104KB, 6 páginas)</p><h3 id="contexto-1" tabindex="-1">Contexto <a class="header-anchor" href="#contexto-1" aria-label="Permalink to &quot;Contexto&quot;">​</a></h3><p>Comparação metódica de <strong>três</strong> algoritmos construtivos em problemas de regressão, com foco em <strong>parcimônia da arquitetura resultante</strong> (número de camadas e neurônios).</p><h3 id="algoritmos-construtivos-comparados-1" tabindex="-1">Algoritmos Construtivos Comparados <a class="header-anchor" href="#algoritmos-construtivos-comparados-1" aria-label="Permalink to &quot;Algoritmos Construtivos Comparados&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Algoritmo</th><th>Abreviação</th><th>Mecanismo</th></tr></thead><tbody><tr><td><strong>A* Heuristic Search</strong></td><td>A*</td><td>Busca heurística no espaço de arquiteturas. Função de ativação: tangente hiperbólica. Permite múltiplas camadas e múltiplos neurônios por camada.</td></tr><tr><td><strong>Cascade-Correlation</strong></td><td>CASCOR</td><td>Adiciona neurônios um a um, congela pesos anteriores. Ativações intermediárias escolhidas de um conjunto fechado (tanh, seno, cosseno, gaussiana, inverso da gaussiana). Saída linear por mínimos quadrados. Treinamento das camadas intermediárias com Quickprop.</td></tr><tr><td><strong>Projection Pursuit Learning</strong></td><td>PPL</td><td>Busca de projeção em subespaço. Usa polinômios de Hermite como funções de ativação em neurônios intermediários. Saída linear.</td></tr></tbody></table><h3 id="problemas-de-teste" tabindex="-1">Problemas de Teste <a class="header-anchor" href="#problemas-de-teste" aria-label="Permalink to &quot;Problemas de Teste&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problema</th><th>N</th><th>Tipo</th></tr></thead><tbody><tr><td>XOR (paridade 2)</td><td>4</td><td>Toy</td></tr><tr><td>sin(x)·cos(2x)</td><td>25</td><td>Toy</td></tr><tr><td>ESP</td><td>75</td><td>Mundo real</td></tr><tr><td>IRIS</td><td>150</td><td>Benchmark</td></tr><tr><td>GLASS</td><td>214</td><td>Benchmark</td></tr><tr><td>SOJA</td><td>116</td><td>Mundo real</td></tr></tbody></table><p>Critério de parada: MSE = 0.01</p><h3 id="achados-principais" tabindex="-1">Achados Principais <a class="header-anchor" href="#achados-principais" aria-label="Permalink to &quot;Achados Principais&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Achado</th><th>Implicação</th></tr></thead><tbody><tr><td><strong>A* e CASCOR nem sempre precisam adicionar neurônios</strong></td><td>A arquitetura mínima já resolve alguns problemas. &quot;Construtivo&quot; não significa &quot;sempre crescer&quot; — significa &quot;crescer só quando necessário&quot;.</td></tr><tr><td><strong>A* sempre escolheu uma única camada intermediária</strong></td><td>Reforça o teorema da aproximação universal (Funayama, 1997). Mais camadas não são necessariamente melhores.</td></tr><tr><td><strong>CASCOR sempre escolheu funções seno ou cosseno</strong></td><td>O conjunto fechado de ativações converge para funções periódicas.</td></tr><tr><td><strong>PPL bom para 1 saída, pobre para múltiplas saídas (IRIS)</strong></td><td>Limitação fundamental do método de projeção — dificuldade com problemas multi-output.</td></tr><tr><td><strong>Parcimônia varia por algoritmo</strong></td><td>Cada algoritmo produz arquiteturas de tamanho diferente para o mesmo problema. Não há &quot;melhor&quot; — há trade-offs.</td></tr></tbody></table><h3 id="limitacao-do-a" tabindex="-1">Limitação do A* <a class="header-anchor" href="#limitacao-do-a" aria-label="Permalink to &quot;Limitação do A\\*&quot;">​</a></h3><p>&quot;A* permite a criação de redes com múltiplas camadas e múltiplos neurônios por camada, <strong>sempre uma rede com uma única camada intermediária foi escolhida</strong>.&quot; — Isso não é necessariamente limitação do A*, mas sim consequência do critério de parada (MSE = 0.01) combinado com o teorema da aproximação universal.</p><h3 id="resumo-1" tabindex="-1">Resumo <a class="header-anchor" href="#resumo-1" aria-label="Permalink to &quot;Resumo&quot;">​</a></h3><p>O paper da UNICAMP é o mais útil porque:</p><ol><li>Comparação controlada (mesmos problemas, mesmos critérios de parada)</li><li>Foco em <strong>parcimônia</strong> — a métrica que mais importa para o T4 (não super-engenheirar o grafo)</li><li>Mostra que algoritmos diferentes produzem arquiteturas diferentes para o mesmo problema — não há solução única</li><li>O PPL é particularmente interessante pela idéia de <strong>projeção em subespaço</strong> (análogo ao operador <code>project</code> do T4)</li></ol><hr><h2 id="mapeamento-para-t4" tabindex="-1">Mapeamento para T4 <a class="header-anchor" href="#mapeamento-para-t4" aria-label="Permalink to &quot;Mapeamento para T4&quot;">​</a></h2><p>O paradigma construtivo mapeia diretamente para os operadores relacionais do ADR-0002:</p><h3 id="operadores-construtivos-×-operadores-t4" tabindex="-1">Operadores Construtivos × Operadores T4 <a class="header-anchor" href="#operadores-construtivos-×-operadores-t4" aria-label="Permalink to &quot;Operadores Construtivos × Operadores T4&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Algoritmo Construtivo</th><th>Estratégia</th><th>Operador T4 Análogo</th></tr></thead><tbody><tr><td><strong>Cascade Correlation</strong></td><td>Adiciona neurônio, congela passado, treina novo contra erro residual</td><td><code>expand(entity, criteria_set)</code> — expande fronteira do subgrafo com novos nós, preservando estrutura interna</td></tr><tr><td><strong>A* Heuristic Search</strong></td><td>Busca guiada por custo no espaço de arquiteturas</td><td><code>find_entity(subgraph_schema)</code> — busca topológica com função de custo (heurística de similaridade)</td></tr><tr><td><strong>Projection Pursuit</strong></td><td>Projeta dados em subespaço otimizado</td><td><code>project(entity, axes)</code> — fatia o subgrafo por eixos, revelando estrutura latente</td></tr><tr><td><strong>Pruning (poda)</strong></td><td>Remove elementos que não contribuem</td><td>Fractal Boundary — rejeita arestas/nós que não passam pelo crivo de consistência</td></tr><tr><td><strong>Tower/Pyramid</strong></td><td>Crescimento hierárquico com reuso de conexões</td><td><code>chain(entity, operator)</code> — composição sequencial de operadores</td></tr></tbody></table><h3 id="ciclo-construtivo-×-ciclo-de-cristalizacao" tabindex="-1">Ciclo Construtivo × Ciclo de Cristalização <a class="header-anchor" href="#ciclo-construtivo-×-ciclo-de-cristalizacao" aria-label="Permalink to &quot;Ciclo Construtivo × Ciclo de Cristalização&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fase Construtiva</th><th>Fase T4</th></tr></thead><tbody><tr><td>Topologia mínima inicial</td><td><strong>Fluida</strong> — grafo mínimo, hipóteses fracas</td></tr><tr><td>Erro residual alto → adiciona unidade</td><td><strong>Proving</strong> — operador <code>expand</code> adiciona nós/arestas</td></tr><tr><td>Treinamento e ajuste fino</td><td><strong>Proving</strong> — refinamento de pesos (confiança)</td></tr><tr><td>Erro abaixo do limiar → para</td><td><strong>Cristalizada</strong> — arquitetura parcimoniosa, confiança alta</td></tr><tr><td>Poda de elementos redundantes</td><td>Contração via Fractal Boundary</td></tr></tbody></table><h3 id="licoes-para-o-t4" tabindex="-1">Lições para o T4 <a class="header-anchor" href="#licoes-para-o-t4" aria-label="Permalink to &quot;Lições para o T4&quot;">​</a></h3><ol><li><p><strong>Parcimônia primeiro:</strong> O teorema da aproximação universal sugere que uma única camada (subgrafo) bem projetada é suficiente. Não adicione complexidade sem justificativa — o operador <code>expand</code> deve ser usado com moderação.</p></li><li><p><strong>Múltiplos algoritmos para o mesmo problema:</strong> Diferentes estratégias de crescimento produzem arquiteturas diferentes. O T4 deve expor múltiplos operadores de descoberta (CASCOR-like vs A*-like vs PPL-like) para que o agente escolha.</p></li><li><p><strong>Critério de parada é tão importante quanto o algoritmo:</strong> O MSE=0.01 define quando o A* para. No T4, o equivalente é o limiar de confiança da Fractal Boundary — que define quando uma entidade transita de Fluida para Cristalizada.</p></li><li><p><strong>Não confunda &quot;construtivo&quot; com &quot;sempre crescer&quot;:</strong> A* e CASCOR mostraram que às vezes a arquitetura mínima já resolve. O T4 deve suportar a decisão de <strong>não expandir</strong>.</p></li><li><p><strong>PPL como Project:</strong> O conceito de projeção em subespaço do PPL (polinômios de Hermite) é análogo direto ao operador <code>project(entity, axes)</code> do ADR-0002 — revelar estrutura latente ao mudar o eixo de observação.</p></li></ol><hr><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>Vargas, E. C., Sousa, H. C., Carvalho, A. C. P. L. F. (1998). &quot;Reconhecimento de Alvos utilizando Redes Neurais Construtivas.&quot; <em>IX SBSR</em>, INPE, 1247-1256.</li><li>Castro, L. N., Iyoda, E. M., Pinheiro, E., Von Zuben, F. (1999). &quot;Redes Neurais Construtivas: Uma Abordagem Comparativa.&quot; <em>IV Brazilian Conference on Neural Networks</em>, ITA, 102-107.</li><li>Fahlman, S. E., Lebiere, C. (1990). &quot;The Cascade-Correlation Learning Architecture.&quot; <em>Advances in Neural Information Processing Systems 2</em>, 524-532.</li><li>Frean, M. (1990). &quot;The Upstart Algorithm: A Method for Constructing and Training Feedforward Neural Networks.&quot; <em>Neural Computation</em>, 2(2), 198-209.</li><li>Parekh, R., Yang, J., Honavar, V. (1997). &quot;Constructive Neural Network Learning Algorithms for Multi-Category Pattern Classification.&quot; <em>Iowa State University Technical Report</em>.</li></ul>',43)])])}const h=o(s,[["render",i]]);export{p as __pageData,h as default};
